    id: 'canonical-image-carousel',
    block: 'React Hooks & Components',
    title: 'Image Carousel',
    timeLimitMin: 10,
    description:
      'Implement an image carousel (slideshow) component with next/previous controls, indicator dots, transition animations, and optional autoplay support.',
    starter:
      'export function ImageCarousel({ images, autoplayInterval = 0 }: { images: string[], autoplayInterval?: number }) {\n  // Ваша реалізація тут\n}',
    solution:
      "import React, { useState, useEffect } from 'react';\n\nexport function ImageCarousel({ images, autoplayInterval = 0 }: { images: string[], autoplayInterval?: number }) {\n  // Оголошення та ініціалізація змінної \"\"\n  const [index, setIndex] = useState(0);\n\n  // Оголошення та ініціалізація змінної \"next\"\n  const next = () => setIndex(prev => (prev === images.length - 1 ? 0 : prev + 1));\n  // Оголошення та ініціалізація змінної \"prev\"\n  const prev = () => setIndex(prev => (prev === 0 ? images.length - 1 : prev - 1));\n\n  useEffect(() => {\n    // Перевірка умови виконання\n    if (autoplayInterval > 0) {\n      // Оголошення та ініціалізація змінної \"interval\"\n      const interval = setInterval(next, autoplayInterval);\n      // Повернення обчисленого значення\n      return () => clearInterval(interval);\n    }\n  }, [autoplayInterval]);\n\n  // Повернення обчисленого значення\n  return (\n    <div className=\"carousel\" style={{ position: 'relative', width: 400, height: 250, overflow: 'hidden' }}>\n      <img src={images[index]} alt=\"Carousel Slide\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />\n      <button onClick={prev} style={{ position: 'absolute', left: 10, top: '50%' }}>Prev</button>\n      <button onClick={next} style={{ position: 'absolute', right: 10, top: '50%' }}>Next</button>\n      <div style={{ position: 'absolute', bottom: 10, left: '50%', transform: 'translateX(-50%)', display: 'flex', gap: 5 }}>\n        // Трансформація елементів масиву\n        {images.map((_, idx) => (\n          <span \n            key={idx} \n            onClick={() => setIndex(idx)} \n            style={{ \n              width: 8, \n              height: 8, \n              borderRadius: '50%', \n              backgroundColor: index === idx ? '#fff' : '#888', \n              cursor: 'pointer' \n            }} \n          />\n        ))}\n      </div>\n    </div>\n  );\n}",
