    title: 'Accordion',
    timeLimitMin: 10,
    description:
      'Implement an Accordion UI component containing multiple expandable/collapsible sections. Support single-expand mode (only one section open at a time) or multi-expand mode.',
    starter:
      'export function Accordion({ items, allowMultiple = false }: { items: AccordionItem[], allowMultiple?: boolean }) {\n  // Ваша реалізація тут\n}',
    solution:
      "import React, { useState } from 'react';\n\ninterface AccordionItem {\n  title: string;\n  content: string;\n}\n\nexport function Accordion({ items, allowMultiple = false }: { items: AccordionItem[], allowMultiple?: boolean }) {\n  // Оголошення та ініціалізація змінної \"\"\n  const [openIndexes, setOpenIndexes] = useState<number[]>([]);\n\n  // Оголошення та ініціалізація змінної \"toggle\"\n  const toggle = (index: number) => {\n    // Перевірка умови виконання\n    if (allowMultiple) {\n      setOpenIndexes(prev => \n        // Фільтрація масиву за заданим критерієм\n        prev.includes(index) ? prev.filter(i => i !== index) : [...prev, index]\n      );\n    } else {\n      setOpenIndexes(prev => prev.includes(index) ? [] : [index]);\n    }\n  };\n\n  // Повернення обчисленого значення\n  return (\n    <div>\n      // Трансформація елементів масиву\n      {items.map((item, idx) => {\n        // Оголошення та ініціалізація змінної \"isOpen\"\n        const isOpen = openIndexes.includes(idx);\n        // Повернення обчисленого значення\n        return (\n          <div key={idx} style={{ border: '1px solid #ccc', margin: '5px 0' }}>\n            <div \n              onClick={() => toggle(idx)} \n              style={{ padding: 10, background: '#eee', cursor: 'pointer', fontWeight: 'bold' }}\n            >\n              {item.title} {isOpen ? '▼' : '▶'}\n            </div>\n            {isOpen && <div style={{ padding: 10 }}>{item.content}</div>}\n          </div>\n        );\n      })}\n    </div>\n  );\n}",
