    block: 'React Hooks & Components',
    title: 'Tabs',
    timeLimitMin: 10,
    description:
      'Build a flexible Tabs component showing a row of clickable tab items and rendering the active content pane accordingly.',
    starter:
      'export function Tabs({ items, defaultTabId }: { items: TabItem[], defaultTabId: string }) {\n  // Ваша реалізація тут\n}',
    solution:
      "import React, { useState } from 'react';\n\ninterface TabItem {\n  id: string;\n  label: string;\n  content: React.ReactNode;\n}\n\nexport function Tabs({ items, defaultTabId }: { items: TabItem[], defaultTabId: string }) {\n  // Оголошення та ініціалізація змінної \"\"\n  const [activeTabId, setActiveTabId] = useState(defaultTabId);\n\n  // Оголошення та ініціалізація змінної \"activeContent\"\n  const activeContent = items.find(t => t.id === activeTabId)?.content;\n\n  // Повернення обчисленого значення\n  return (\n    <div>\n      <div style={{ display: 'flex', borderBottom: '1px solid #ccc' }}>\n        // Трансформація елементів масиву\n        {items.map(tab => (\n          <button\n            key={tab.id}\n            onClick={() => setActiveTabId(tab.id)}\n            style={{\n              padding: '10px 20px',\n              border: 'none',\n              borderBottom: activeTabId === tab.id ? '2px solid blue' : 'none',\n              background: 'none',\n              cursor: 'pointer',\n              fontWeight: activeTabId === tab.id ? 'bold' : 'normal'\n            }}\n          >\n            {tab.label}\n          </button>\n        ))}\n      </div>\n      <div style={{ padding: 20 }}>\n        {activeContent}\n      </div>\n    </div>\n  );\n}",
