    description:
      'Implement a pub/sub Event Emitter class in JavaScript. It should support subscribing to events, unsubscribing from events, and publishing events with optional arguments.',
    starter: 'class EventEmitter {\n  // Ваша реалізація тут\n}',
    solution:
      "class EventEmitter {\n  constructor() {\n    // Реєстр подій: ключ - ім'я події, значення - Set з колбеками\n    this.events = new Map();\n  }\n\n  subscribe(eventName, callback) {\n    // Якщо подія реєструється вперше, створюємо новий Set\n    if (!this.events.has(eventName)) {\n      this.events.set(eventName, new Set());\n    }\n    \n    // Додаємо колбек до списку слухачів події\n    const callbacks = this.events.get(eventName);\n    callbacks.add(callback);\n\n    // Повертаємо об'єкт з методом unsubscribe для зручного скасування підписки\n    return {\n      unsubscribe: () => {\n        callbacks.delete(callback); // Видаляємо слухача\n        // Якщо більше немає підписників, видаляємо подію з реєстру для економії пам'яті\n        if (callbacks.size === 0) {\n          this.events.delete(eventName);\n        }\n      }\n    };\n  }\n\n  emit(eventName, ...args) {\n    // Отримуємо всіх слухачів для події\n    const callbacks = this.events.get(eventName);\n    if (callbacks) {\n      // Викликаємо кожен зареєстрований колбек з переданими аргументами\n      callbacks.forEach(cb => cb(...args));\n    }\n  }\n}",
