      '// Головна функція/клас для: Binary Tree Vertical Traversal\nfunction verticalOrder(root) {\n  // Перевірка на базовий або крайовий випадок (null / undefined / порожнє значення)\n  if (!root) return [];\n  \n  // Оголошення та ініціалізація змінної "columnMap"\n  const columnMap = {};\n  // Оголошення та ініціалізація змінної "queue"\n  const queue = [{ node: root, col: 0 }];\n  // Оголошення та ініціалізація змінної "minCol"\n  let minCol = 0;\n  // Оголошення та ініціалізація змінної "maxCol"\n  let maxCol = 0;\n  \n  // Цикл виконання, поки умова є істинною\n  while (queue.length > 0) {\n    // Оголошення та ініціалізація змінної ""\n    const { node, col } = queue.shift();\n    \n    // Перевірка на базовий або крайовий випадок (null / undefined / порожнє значення)\n    if (!columnMap[col]) {\n      columnMap[col] = [];\n    }\n    columnMap[col].push(node.val);\n    \n    minCol = Math.min(minCol, col);\n    maxCol = Math.max(maxCol, col);\n    \n    // Перевірка умови виконання\n    if (node.left) queue.push({ node: node.left, col: col - 1 });\n    // Перевірка умови виконання\n    if (node.right) queue.push({ node: node.right, col: col + 1 });\n  }\n  \n  // Оголошення та ініціалізація змінної "result"\n  const result = [];\n  // Цикл перебору елементів\n  for (let i = minCol; i <= maxCol; i++) {\n    // Перевірка умови виконання\n    if (columnMap[i]) {\n      result.push(columnMap[i]);\n    }\n  }\n  \n  // Повернення обчисленого значення\n  return result;\n}',
