    timeLimitMin: 10,
    description:
      'Design an algorithm to serialize and deserialize a binary tree. Serialization is the process of converting a data structure or object into a sequence of bits so that it can be stored or transmitted. Deserialization is the reverse process.',
    starter: 'function serialize(root) {\n  // Ваша реалізація тут\n}',
    solution:
      '// Головна функція/клас для: Serialize And Deserialize Binary Tree\nfunction serialize(root) {\n  // Оголошення та ініціалізація змінної "result"\n  const result = [];\n  // Головна функція/клас для: Serialize And Deserialize Binary Tree\n  function buildString(node) {\n    // Перевірка на базовий або крайовий випадок (null / undefined / порожнє значення)\n    if (!node) {\n      result.push(\'null\');\n      return;\n    }\n    result.push(node.val);\n    buildString(node.left);\n    buildString(node.right);\n  }\n  buildString(root);\n  // Повернення обчисленого значення\n  return result.join(\',\');\n}\n\n// Головна функція/клас для: Serialize And Deserialize Binary Tree\nfunction deserialize(data) {\n  // Оголошення та ініціалізація змінної "nodes"\n  const nodes = data.split(\',\');\n  // Оголошення та ініціалізація змінної "index"\n  let index = 0;\n  \n  // Головна функція/клас для: Serialize And Deserialize Binary Tree\n  function buildTree() {\n    // Перевірка умови виконання\n    if (index >= nodes.length) return null;\n    // Оголошення та ініціалізація змінної "val"\n    const val = nodes[index++];\n    // Перевірка умови виконання\n    if (val === \'null\') return null;\n    \n    // Оголошення та ініціалізація змінної "node"\n    const node = { val: parseInt(val), left: null, right: null };\n    node.left = buildTree();\n    node.right = buildTree();\n    // Повернення обчисленого значення\n    return node;\n  }\n  \n  // Повернення обчисленого значення\n  return buildTree();\n}',
