    solution:
      'import React, { useState } from \'react\';\n\nexport function MultiStepForm({ onSubmit }: { onSubmit: (data: any) => void }) {\n  // Оголошення та ініціалізація змінної ""\n  const [step, setStep] = useState(1);\n  // Оголошення та ініціалізація змінної ""\n  const [formData, setFormData] = useState({\n    username: \'\',\n    email: \'\',\n    password: \'\'\n  });\n\n  // Оголошення та ініціалізація змінної "handleChange"\n  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {\n    setFormData({ ...formData, [e.target.name]: e.target.value });\n  };\n\n  // Оголошення та ініціалізація змінної "next"\n  const next = () => setStep(prev => prev + 1);\n  // Оголошення та ініціалізація змінної "prev"\n  const prev = () => setStep(prev => prev - 1);\n  // Оголошення та ініціалізація змінної "handleSubmit"\n  const handleSubmit = (e: React.FormEvent) => {\n    e.preventDefault();\n    onSubmit(formData);\n  };\n\n  // Повернення обчисленого значення\n  return (\n    <form onSubmit={handleSubmit} style={{ width: 300, display: \'flex\', flexDirection: \'column\', gap: 15 }}>\n      <h3>Step {step} of 3</h3>\n      {step === 1 && (\n        <div>\n          <label>Username: </label>\n          <input name="username" value={formData.username} onChange={handleChange} required />\n        </div>\n      )}\n      {step === 2 && (\n        <div>\n          <label>Email: </label>\n          <input name="email" type="email" value={formData.email} onChange={handleChange} required />\n        </div>\n      )}\n      {step === 3 && (\n        <div>\n          <label>Password: </label>\n          <input name="password" type="password" value={formData.password} onChange={handleChange} required />\n        </div>\n      )}\n      <div style={{ display: \'flex\', gap: 10 }}>\n        {step > 1 && <button type="button" onClick={prev}>Back</button>}\n        {step < 3 ? (\n          <button type="button" onClick={next}>Next</button>\n        ) : (\n          <button type="submit">Submit</button>\n        )}\n      </div>\n    </form>\n  );\n}',
