    solution:
      '/**\n * @param {any[]} arr\n */\nfunction deduplicate(arr) {\n  const map = new Map();\n\n  for (let i = 0; i < arr.length; i++) {\n    if (map.has(arr[i])) {\n      arr.splice(i, 1);\n      i--;\n      continue;\n    }\n    map.set(arr[i], 1);\n  }\n}',
