    solution:
      "/**\n * @param {object} obj\n * @param {string} methodName\n */\nfunction spyOn(obj, methodName) {\n  const spy = {\n    calls: [],\n  };\n\n  const originalMethod = obj[methodName];\n  if (!originalMethod || typeof originalMethod !== 'function') {\n    throw new Error();\n  }\n\n  obj[methodName] = (...args) => {\n    spy.calls.push(args);\n    originalMethod.apply(obj, args);\n  };\n\n  return spy;\n}",
