    block: 'JS Functions / Polyfills',
    title: 'Cache With Time Limit',
    timeLimitMin: 10,
    description:
      'Write a class that allows getting and setting key-value pairs, but with a time-to-live (TTL) limit on each key. When the TTL expires, the key should become inaccessible.',
    starter: 'class TimeLimitedCache {\n  // Ваша реалізація тут\n}',
    solution:
      '// Головна функція/клас для: Cache With Time Limit\nclass TimeLimitedCache {\n  constructor() {\n    this.cache = new Map();\n  }\n\n  set(key, value, duration) {\n    // Оголошення та ініціалізація змінної "now"\n    const now = Date.now();\n    // Оголошення та ініціалізація змінної "hasKey"\n    const hasKey = this.cache.has(key) && this.cache.get(key).expiry > now;\n    \n    // Перевірка умови виконання\n    if (this.cache.has(key)) {\n      // Скасування активного таймера\n      clearTimeout(this.cache.get(key).timer);\n    }\n    \n    // Оголошення та ініціалізація змінної "timer"\n    const timer = setTimeout(() => {\n      this.cache.delete(key);\n    }, duration);\n    \n    this.cache.set(key, {\n      value,\n      expiry: now + duration,\n      timer\n    });\n    \n    // Повернення обчисленого значення\n    return hasKey;\n  }\n\n  get(key) {\n    // Оголошення та ініціалізація змінної "now"\n    const now = Date.now();\n    // Перевірка умови виконання\n    if (this.cache.has(key)) {\n      // Оголошення та ініціалізація змінної "entry"\n      const entry = this.cache.get(key);\n      // Перевірка умови виконання\n      if (entry.expiry > now) {\n        // Повернення обчисленого значення\n        return entry.value;\n      }\n    }\n    // Повернення обчисленого значення\n    return -1;\n  }\n\n  count() {\n    // Оголошення та ініціалізація змінної "now"\n    const now = Date.now();\n    // Оголошення та ініціалізація змінної "cnt"\n    let cnt = 0;\n    // Цикл перебору елементів\n    for (const [_, entry] of this.cache.entries()) {\n      // Перевірка умови виконання\n      if (entry.expiry > now) cnt++;\n    }\n    // Повернення обчисленого значення\n    return cnt;\n  }\n}',
