    solution:
      '// Головна функція/клас для: Execute Asynchronous Functions In Parallel\nfunction promiseAll(functions) {\n  // Повернення обчисленого значення\n  return new Promise((resolve, reject) => {\n    // Оголошення та ініціалізація змінної "results"\n    const results = [];\n    // Оголошення та ініціалізація змінної "completed"\n    let completed = 0;\n    \n    // Перевірка умови виконання\n    if (functions.length === 0) {\n      resolve(results);\n      return;\n    }\n    \n    // Головна функція/клас для: Execute Asynchronous Functions In Parallel\n    functions.forEach((fn, idx) => {\n      fn()\n        .then(val => {\n          results[idx] = val;\n          completed++;\n          // Перевірка умови виконання\n          if (completed === functions.length) {\n            resolve(results);\n          }\n        })\n        .catch(reject);\n    });\n  });\n}',
